data.content:
Important correction: MSTest doesn't have `Assert.StartsWith` / `Assert.EndsWith`. Those live on the **`StringAssert`** class:

- `StringAssert.StartsWith(string, substring)`
- `StringAssert.EndsWith(string, substring)`
- `StringAssert.Contains(string, substring)`
- `StringAssert.Matches(string, regex)`

Here are the tests using the correct API:

```csharp
using System.Text.RegularExpressions;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using Contoso.Text;

namespace Contoso.Text.Tests;

[TestClass]
public sealed class StringFormatterTests
{
    private readonly StringFormatter _formatter = new();

    // ── FormatPhoneNumber ──────────────────────────────────────

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_ReturnsFormattedNumber()
    {
        var result = _formatter.FormatPhoneNumber("2125551234");

        Assert.AreEqual("(212) 555-1234", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_Result_StartsWithAreaCodeInParens()
    {
        var result = _formatter.FormatPhoneNumber("8005559999");

        StringAssert.StartsWith(result, "(800)");
    }

    [TestMethod]
    public void FormatPhoneNumber_Result_EndsWithLastFourDigits()
    {
        var result = _formatter.FormatPhoneNumber("2125551234");

        StringAssert.EndsWith(result, "-1234");
    }

    [TestMethod]
    public void FormatPhoneNumber_Result_MatchesExpectedPattern()
    {
        var result = _formatter.FormatPhoneNumber("2125551234");

        StringAssert.Matches(result, new Regex(@"^\(\d{3}\) \d{3}-\d{4}$"));
    }

    [TestMethod]
    public void FormatPhoneNumber_NullInput_ThrowsArgumentNullException()
    {
        Assert.ThrowsException<ArgumentNullException>(
            () => _formatter.FormatPhoneNumber(null!));
    }

    [TestMethod]
    [DataRow("123")]
    [DataRow("12345678901")]
    public void FormatPhoneNumber_WrongLength_ThrowsArgumentException(string digits)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _formatter.FormatPhoneNumber(digits));
    }

    // ── BuildGreeting ──────────────────────────────────────────

    [TestMethod]
    public void BuildGreeting_DefaultTitle_ReturnsMrGreeting()
    {
        var result = _formatter.BuildGreeting("Smith");

        Assert.AreEqual("Dear Mr. Smith,", result);
    }

    [TestMethod]
    public void BuildGreeting_CustomTitle_UsesTitleProvided()
    {
        var result = _formatter.BuildGreeting("Johnson", "Dr.");

        Assert.AreEqual("Dear Dr. Johnson,", result);
    }

    [TestMethod]
    public void BuildGreeting_Result_StartsWithDear()
    {
        var result = _formatter.BuildGreeting("Doe");

        StringAssert.StartsWith(result, "Dear ");
    }

    [TestMethod]
    public void BuildGreeting_Result_EndsWithComma()
    {
        var result = _formatter.BuildGreeting("Doe", "Ms.");

        StringAssert.EndsWith(result, ",");
    }

    [TestMethod]
    public void BuildGreeting_Result_ContainsName()
    {
        var result = _formatter.BuildGreeting("Williams");

        StringAssert.Contains(result, "Williams");
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void BuildGreeting_NullOrWhitespaceName_Throws(string? name)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _formatter.BuildGreeting(name!));
    }

    // ── GenerateSlug ───────────────────────────────────────────

    [TestMethod]
    public void GenerateSlug_SimpleTitle_ReturnsLowercaseHyphenated()
    {
        var result = _formatter.GenerateSlug("Hello World");

        Assert.AreEqual("hello-world", result);
    }

    [TestMethod]
    public void GenerateSlug_SpecialCharacters_ReplacedWithHyphens()
    {
        var result = _formatter.GenerateSlug("C# is Fun!!!");

        Assert.AreEqual("c-is-fun", result);
    }

    [TestMethod]
    public void GenerateSlug_LeadingTrailingWhitespace_IsTrimmed()
    {
        var result = _formatter.GenerateSlug("  some title  ");

        Assert.AreEqual("some-title", result);
    }

    [TestMethod]
    public void GenerateSlug_Result_MatchesSlugPattern()
    {
        var result = _formatter.GenerateSlug("My Post Title!");

        StringAssert.Matches(result, new Regex(@"^[a-z0-9]+(-[a-z0-9]+)*$"));
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void GenerateSlug_NullOrWhitespace_Throws(string? title)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _formatter.GenerateSlug(title!));
    }

    // ── FormatCurrency ─────────────────────────────────────────

    [TestMethod]
    public void FormatCurrency_DefaultSymbol_ReturnsDollarFormatted()
    {
        var result = _formatter.FormatCurrency(19.99m);

        Assert.AreEqual("$19.99", result);
    }

    [TestMethod]
    public void FormatCurrency_CustomSymbol_UsesSymbolProvided()
    {
        var result = _formatter.FormatCurrency(9.5m, "€");

        Assert.AreEqual("€9.50", result);
    }

    [TestMethod]
    public void FormatCurrency_Result_StartsWithSymbol()
    {
        var result = _formatter.FormatCurrency(100m, "£");

        StringAssert.StartsWith(result, "£");
    }

    [TestMethod]
    public void FormatCurrency_WholeNumber_EndsWithTwoDecimalPlaces()
    {
        var result = _formatter.FormatCurrency(42m);

        StringAssert.EndsWith(result, ".00");
    }

    [TestMethod]
    public void FormatCurrency_NegativeAmount_ContainsMinusSign()
    {
        var result = _formatter.FormatCurrency(-5.75m);

        StringAssert.Contains(result, "-");
    }
}
```

**Key takeaway:** MSTest splits string assertions into a separate `StringAssert` class:

| Method | Class |
|---|---|
| `StartsWith` | `StringAssert` |
| `EndsWith` | `StringAssert` |
| `Contains` | `StringAssert` |
| `Matches` | `StringAssert` |
| `AreEqual`, `ThrowsException`, etc. | `Assert` |
